module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
    parameter idle = 2'b00;
    parameter s1_red = 2'b01;
    parameter s2_yellow = 2'b10;
    parameter s3_green = 2'b11;
    reg [1:0] state;
    reg [1:0] next_state;
    reg [7:0] cnt;
    reg [7:0] next_cnt;
    reg next_red;
    reg next_yellow;
    reg next_green;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= idle;
        end else begin
            state <= next_state;
        end
    end
    always @(*) begin
        case (state)
            idle: begin
                next_state = s1_red;
            end
            s1_red: begin
                if (cnt == 60) begin
                    next_state = s3_green;
                end else begin
                    next_state = s1_red;
                end
            end
            s2_yellow: begin
                if (cnt == 5) begin
                    next_state = s1_red;
                end else begin
                    next_state = s2_yellow;
                end
            end
            s3_green: begin
                if (cnt == 10) begin
                    next_state = s2_yellow;
                end else begin
                    next_state = s3_green;
                end
            end
            default: begin
                next_state = idle;
            end
        endcase
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 10;
        end else begin
            cnt <= next_cnt;
        end
    end
    always @(*) begin
        case (cnt)
            10: begin
                if (pass_request) begin
                    next_cnt = 60;
                end else begin
                    next_cnt = 10;
                end
            end
            60: begin
                next_cnt = 5;
            end
            5: begin
                next_cnt = 10;
            end
            1: begin
                next_cnt = 10;
            end
            default: begin
                next_cnt = cnt - 1;
            end
        endcase
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            red <= 0;
            next_yellow = 0;
            next_green = 0;
        end else begin
            red <= next_red;
            yellow <= next_yellow;
            green <= next_green;
        end
    end
    always @(*) begin
        case (state)
            idle: begin
                next_red = 0;
            end
            s1_red: begin
                next_red = 1;
            end
            s2_yellow: begin
                next_yellow = 1;
            end
            s3_green: begin
                next_green = 1;
            end
            default: begin
                next_red = 0;
            end
        endcase
    end
    always @(*) begin
        case (state)
            idle: begin
                next_yellow = 0;
            end
            s1_red: begin
                next_yellow = 0;
            end
            s2_yellow: begin
                next_yellow = 1;
            end
            s3_green: begin
                next_yellow = 0;
            end
            default: begin
                next_yellow = 0;
            end
        endcase
    end
    always @(*) begin
        case (state)
            idle: begin
                next_green = 0;
            end
            s1_red: begin
                next_green = 0;
            end
            s2_yellow: begin
                next_green = 0;
            end
            s3_green: begin
                next_green = 1;
            end
            default: begin
                next_green = 0;
            end
        endcase
    end
endmodule

module multi_16bit
(
    input clk,
    input rst_n,
    input start,
    input ain,
    input bin,
    output yout,
    output done
);

reg [15:0] areg, breg;
reg [31:0] yout_r;
reg [4:0] i;
reg done_r;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        i <= 0;
    end
    else if (start && i < 17) begin
        i <= i + 1;
    end
    else begin
        i <= 0;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        done_r <= 0;
    end
    else if (i == 16) begin
        done_r <= 1;
    end
    else if (i == 17) begin
        done_r <= 0;
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        areg <= 0;
        breg <= 0;
        yout_r <= 0;
    end
    else if (start) begin
        areg <= ain;
        breg <= bin;
        yout_r <= 0;
    end
    else begin
        if (i > 0) begin
            if (breg[i-1]) begin
                yout_r <= yout_r + (areg << (i-1));
            end
        end
    end
end

assign yout = yout_r;
assign done = done_r;

endmodule

module multi_pipe_8bit
(
    input clk,
    input rst_n,
    input mul_en_in,
    input mul_a,
    input mul_b,
    output mul_en_out,
    output mul_out
);
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] partial_products [7:0];
reg [15:0] sum [7:0];
reg [2:0] stage;
reg mul_en_out_reg;
always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        mul_a_reg <= 8'b0;
        mul_b_reg <= 8'b0;
        mul_en_out_reg <= 1'b0;
        stage <= 3'b0;
        for (int i = 0; i < 8; i++) begin
            partial_products[i] <= 16'b0;
            sum[i] <= 16'b0;
        end
    end else begin
        mul_en_out_reg <= mul_en_in;
        if (mul_en_in) begin
            mul_a_reg <= mul_a;
            mul_b_reg <= mul_b;
            for (int i = 0; i < 8; i++) begin
                partial_products[i] <= mul_a_reg[i] ? {8'b0, mul_b_reg} << i : 16'b0;
            end
            stage <= 3'b111;
        end else begin
            for (int i = 0; i < 8; i++) begin
                sum[i] <= partial_products[i] + (i == 0 ? 16'b0 : sum[i-1]);
            end
            stage <= stage - 1;
        end
    end
end
assign mul_en_out = mul_en_out_reg;
assign mul_out = sum[7];
endmodule

module parallel2serial
(
    input clk,
    input rst_n,
    input [3:0] d,
    output valid_out,
    output dout
);

reg [3:0] data;
reg [1:0] cnt;
reg valid;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        data <= 4'b0;
        cnt <= 2'b0;
        valid <= 1'b0;
    end
    else begin
        if (cnt == 2'b11) begin
            data <= d;
            cnt <= 2'b0;
            valid <= 1'b1;
        end
        else begin
            cnt <= cnt + 2'b1;
            valid <= 1'b0;
            data <= {data[2:0], data[3]};
        end
    end
end

assign dout = data[3];
assign valid_out = valid;

endmodule

