module alu
(
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);
    parameter ADD = 6'b100000;
    parameter ADDU = 6'b100001;
    parameter SUB = 6'b100010;
    parameter SUBU = 6'b100011;
    parameter AND = 6'b100100;
    parameter OR = 6'b100101;
    parameter XOR = 6'b100110;
    parameter NOR = 6'b100111;
    parameter SLT = 6'b101010;
    parameter SLTU = 6'b101011;
    parameter SLL = 6'b000000;
    parameter SRL = 6'b000010;
    parameter SRA = 6'b000011;
    parameter SLLV = 6'b000100;
    parameter SRLV = 6'b000110;
    parameter SRAV = 6'b000111;
    parameter LUI = 6'b001111;
    wire signed [31:0] a_signed = a;
    wire signed [31:0] b_signed = b;
    reg [31:0] res;
    reg [31:0] res_signed;
    assign r = res;
    assign zero = res == 0;
    assign carry = res[32];
    assign negative = res_signed[31];
    assign overflow = res_signed[31] ^ res_signed[30];
    assign flag = res_signed[31];
    always @(*) begin
        case (aluc)
            ADD: res = a_signed + b_signed;
            ADDU: res = a + b;
            SUB: res = a_signed - b_signed;
            SUBU: res = a - b;
            AND: res = a & b;
            OR: res = a | b;
            XOR: res = a ^ b;
            NOR: res = ~(a | b);
            SLT: res = a_signed < b_signed;
            SLTU: res = a < b;
            SLL: res = a_signed << b[4:0];
            SRL: res = a_signed >> b[4:0];
            SRA: res = a_signed >>> b[4:0];
            SLLV: res = a_signed << b[4:0];
            SRLV: res = a_signed >> b[4:0];
            SRAV: res = a_signed >>> b[4:0];
            LUI: res = {b[15:0], 16'b0};
            default: res = 0;
        endcase
    end
endmodule

module edge_detect
(
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);
    parameter [1:0] ZERO = 2'b00, ONE = 2'b01;
    reg [1:0] state;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            state <= ZERO;
        else begin
            case (state)
                ZERO: begin
                    if (a == 1)
                        state <= ONE;
                    else
                        state <= ZERO;
                end
                ONE: begin
                    if (a == 0)
                        state <= ZERO;
                    else
                        state <= ONE;
                end
            endcase
        end
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rise <= 0;
            down <= 0;
        end else begin
            if (state == ZERO && a == 1) begin
                rise <= 1;
                down <= 0;
            end else if (state == ONE && a == 0) begin
                rise <= 0;
                down <= 1;
            end else begin
                rise <= 0;
                down <= 0;
            end
        end
    end
endmodule

