module asyn_fifo #(
    parameter WIDTH = 8,
    parameter DEPTH = 16
)(
    input wclk,
    input rclk,
    input wrstn,
    input rrstn,
    input winc,
    input rinc,
    input [WIDTH-1:0] wdata,
    output reg wfull,
    output reg rempty,
    output reg [WIDTH-1:0] rdata
);

localparam ADDR_WIDTH = $clog2(DEPTH);

reg [ADDR_WIDTH-1:0] wptr, rptr;
reg [ADDR_WIDTH:0] wptr_gray, rptr_gray;
reg [ADDR_WIDTH:0] wptr_gray_rsync, rptr_gray_wsync;

// Dual-port RAM for data storage
reg [WIDTH-1:0] ram [DEPTH-1:0];
wire [WIDTH-1:0] rdata_wire;

// Write controller
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        wptr <= 0;
        wptr_gray <= 0;
        wfull <= 0;
    end else begin
        if (winc && !wfull) begin
            ram[wptr] <= wdata;
            wptr <= wptr + 1;
            wptr_gray <= (wptr_gray + 1) ^ (wptr_gray + 1 >> 1);
        end
        wfull <= (wptr_gray == (rptr_gray_wsync >> 1)) && (wptr != rptr);
    end
end

// Read controller
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        rptr <= 0;
        rptr_gray <= 0;
        rempty <= 1;
        rdata <= 0;
    end else begin
        if (rinc && !rempty) begin
            rptr <= rptr + 1;
            rptr_gray <= (rptr_gray + 1) ^ (rptr_gray + 1 >> 1);
        end
        rdata <= rdata_wire;
        rempty <= (rptr_gray == wptr_gray_rsync) && (rptr == wptr);
    end
end

// Read pointer synchronizer
always @(posedge rclk or negedge rrstn) begin
    if (!rrstn) begin
        wptr_gray_rsync <= 0;
    end else begin
        wptr_gray_rsync <= wptr_gray;
    end
end

// Write pointer synchronizer
always @(posedge wclk or negedge wrstn) begin
    if (!wrstn) begin
        rptr_gray_wsync <= 0;
    end else begin
        rptr_gray_wsync <= rptr_gray;
    end
end

// Read data output
assign rdata_wire = ram[rptr];

endmodule

