    input clk_a,
    input clk_b,
    input arstn,
    input brstn,
    input [3:0] data_in,
    input data_en,
    output reg [3:0] dataout
);
// data register
reg [3:0] data_reg;
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        data_reg <= 4'b0;
    end else begin
        data_reg <= data_in;
    end
end
// enable data register
reg [3:0] en_data_reg;
always @(posedge clk_a or negedge arstn) begin
    if (!arstn) begin
        en_data_reg <= 4'b0;
    end else begin
        en_data_reg <= data_en;
    end
end
// enable control registers
reg [3:0] en_clap_one;
reg [3:0] en_clap_two;
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        en_clap_one <= 4'b0;
        en_clap_two <= 4'b0;
    end else begin
        en_clap_one <= en_data_reg;
        en_clap_two <= en_clap_one;
    end
end
// output assignment
always @(posedge clk_b or negedge brstn) begin
    if (!brstn) begin
        dataout <= 4'b0;
    end else if (en_clap_two) begin
        dataout <= data_reg;
    end else begin
        dataout <= dataout;
    end
end
